# Unit Tests for `is_palindrome`

```python
import pytest


def is_palindrome(s: str) -> bool:
    s = s.lower().replace(' ', '')
    return s == s[::-1]


class TestIsPalindromeHappyPath:
    """Tests for typical, expected use cases."""

    def test_simple_palindrome_lowercase(self):
        assert is_palindrome("racecar") is True

    def test_simple_palindrome_uppercase(self):
        assert is_palindrome("RACECAR") is True

    def test_mixed_case_palindrome(self):
        assert is_palindrome("RaceCar") is True

    def test_palindrome_with_spaces(self):
        assert is_palindrome("nurses run") is True

    def test_palindrome_with_multiple_spaces(self):
        assert is_palindrome("a man a plan a canal panama") is True

    def test_non_palindrome_simple(self):
        assert is_palindrome("hello") is False

    def test_non_palindrome_mixed_case(self):
        assert is_palindrome("Hello") is False

    def test_non_palindrome_with_spaces(self):
        assert is_palindrome("hello world") is False


class TestIsPalindromeEdgeCases:
    """Tests for edge cases."""

    def test_empty_string(self):
        # An empty string is technically a palindrome (equal to its reverse).
        assert is_palindrome("") is True

    def test_single_character(self):
        assert is_palindrome("a") is True

    def test_single_uppercase_character(self):
        assert is_palindrome("Z") is True

    def test_single_space(self):
        # After stripping space, becomes empty string -> palindrome.
        assert is_palindrome(" ") is True

    def test_only_spaces(self):
        assert is_palindrome("     ") is True

    def test_two_same_characters(self):
        assert is_palindrome("aa") is True

    def test_two_different_characters(self):
        assert is_palindrome("ab") is False

    def test_palindrome_with_leading_trailing_spaces(self):
        assert is_palindrome("  racecar  ") is True

    def test_palindrome_with_numbers(self):
        assert is_palindrome("12321") is True

    def test_non_palindrome_with_numbers(self):
        assert is_palindrome("12345") is False

    def test_alphanumeric_palindrome(self):
        assert is_palindrome("a1b1a") is True

    def test_punctuation_not_stripped(self):
        # Function only strips spaces, not punctuation.
        # "A man, a plan, a canal: Panama" has commas/colons -> not a palindrome.
        assert is_palindrome("A man, a plan, a canal: Panama") is False

    def test_palindrome_preserves_punctuation_check(self):
        # "?!?" reversed is "?!?" -> palindrome.
        assert is_palindrome("?!?") is True

    def test_unicode_palindrome(self):
        assert is_palindrome("éøøé") is True

    def test_unicode_non_palindrome(self):
        assert is_palindrome("éøá") is False

    def test_case_with_all_uppercase_non_palindrome(self):
        assert is_palindrome("HELLO") is False

    def test_long_palindrome(self):
        s = "a" * 1000
        assert is_palindrome(s) is True

    def test_long_non_palindrome(self):
        s = "a" * 999 + "b"
        assert is_palindrome(s) is False

    def test_tab_character_not_stripped(self):
        # Function only strips ' ' (space), not other whitespace.
        # "ab\tba" reversed is "ab\tba" -> palindrome.
        assert is_palindrome("ab\tba") is True

    def test_newline_not_stripped(self):
        # "ab\nba" reversed is "ab\nba" -> palindrome.
        assert is_palindrome("ab\nba") is True

    def test_newline_breaks_palindrome(self):
        # "abc\n" reversed is "\ncba" -> not a palindrome.
        assert is_palindrome("abc\n") is False


class TestIsPalindromeErrorCases:
    """Tests for invalid input types."""

    def test_none_raises_attribute_error(self):
        with pytest.raises(AttributeError):
            is_palindrome(None)

    def test_integer_raises_attribute_error(self):
        with pytest.raises(AttributeError):
            is_palindrome(12321)

    def test_list_raises_attribute_error(self):
        with pytest.raises(AttributeError):
            is_palindrome(["r", "a", "r"])

    def test_dict_raises_attribute_error(self):
        with pytest.raises(AttributeError):
            is_palindrome({"a": 1})

    def test_bytes_raises_type_error(self):
        # bytes has .lower() and .replace(), but replace(' ', '') with str
        # arg raises TypeError because bytes needs bytes args.
        with pytest.raises(TypeError):
            is_palindrome(b"racecar")


@pytest.mark.parametrize("text,expected", [
    ("racecar", True),
    ("level", True),
    ("madam", True),
    ("noon", True),
    ("hello", False),
    ("python", False),
    ("", True),
    ("a", True),
    ("ab", False),
    ("Was it a car or a cat I saw", False),  # has punctuation? No, but case handled
    ("No lemon no melon", True),
    ("12321", True),
    ("12345", False),
])
def test_is_palindrome_parametrized(text, expected):
    assert is_palindrome(text) is expected
